    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    uchar is_leaf;
    int num_keys;
} knode;

__kernel void findRangeK(const long maxheight,
                         __global knode *knodes,
                         const long knodes_elem,
                         __global long *currKnode,
                         __global long *offset,
                         __global long *lastKnode,
                         __global long *offset_2,
                         __global int *start,
                         __global int *end,
                         __global int *recstart,
                         __global int *reclength) {
    const int thid = (int)get_local_id(0);
    const int bid = (int)get_group_id(0);

    int i;
    for (i = 0; i < maxheight; i++) {
        long cknode = currKnode[bid];
        long lknode = lastKnode[bid];
        int s = start[bid];
        int e = end[bid];

        if ((knodes[cknode].keys[thid] <= s) &&
            (s < knodes[cknode].keys[thid + 1])) {
            int index = knodes[cknode].indices[thid];
            if (knodes_elem > (long)index) {
                offset[bid] = (long)index;
            }
        }

        if ((e >= knodes[lknode].keys[thid]) &&
            (e < knodes[lknode].keys[thid + 1])) {
            int index2 = knodes[lknode].indices[thid];
            if (knodes_elem > (long)index2) {
                offset_2[bid] = (long)index2;
            }
        }

        barrier(CLK_GLOBAL_MEM_FENCE);

        if (thid == 0) {
            currKnode[bid] = offset[bid];
            lastKnode[bid] = offset_2[bid];
        }

        barrier(CLK_GLOBAL_MEM_FENCE);
    }

    if (knodes[currKnode[bid]].keys[thid] == start[bid]) {
        recstart[bid] = knodes[currKnode[bid]].indices[thid];
    }

    barrier(CLK_GLOBAL_MEM_FENCE);

    if (knodes[lastKnode[bid]].keys[thid] == end[bid]) {
        reclength[bid] = knodes[lastKnode[bid]].indices[thid] - recstart[bid] + 1;
    }
}
